  "description": "Render ANSI text-style attributes into nested HTML markup and close each style when its matching reset code is received.",
  "cases": [
    {
      "input": {"operation":"render_html","palette":"xterm","text":"\u001b[1mhello world"},
      "expected_output": "<b>hello world</b>"
    },
    {
      "input": {"operation":"render_html","palette":"xterm","text":"\u001b[4mhello world"},
      "expected_output": "<u>hello world</u>"
    },
    {
      "input": {"operation":"render_html","palette":"xterm","text":"\u001b[21mhello world"},
      "expected_output": "<span style=\"border-bottom: 3px double;\">hello world</span>"
    },
    {
      "input": {"operation":"render_html","palette":"xterm","text":"\u001b[3mhello world\u001b[23mnormal"},
      "expected_output": "<i>hello world</i>normal"
    },
    {
      "input": {"operation":"render_html","palette":"xterm","text":"\u001b[9mhello world\u001b[29mnormal"},
      "expected_output": "<span style=\"text-decoration: line-through;\">hello world</span>normal"
    },
    {
      "input": {"operation":"render_html","palette":"xterm","text":"\u001b[51mhello world\u001b[54mnormal"},
